solution_code:
#include <iostream>

void accumulate(int& total, int delta) {
    total = total + delta;
}

int main() {
    int n;
    std::cin >> n;

    int total = 0;
    for (int i = 0; i < n; ++i) {
        int delta;
        std::cin >> delta;
        accumulate(total, delta);
    }

    std::cout << total << '\n';
    return 0;
}

