solution_code:
#include <iostream>

void printSumAndProduct(const int& a, int b) {
    std::cout << "sum: " << a + b << '\n';
    std::cout << "product: " << a * b << '\n';
}

int main() {
    int x, y;
    std::cin >> x >> y;
    printSumAndProduct(x, y);
    return 0;
}
